mapper.select:
select t.title, t.content, t.like_count, t.collect_count, t.comment_count, t.id as postId, u.id as userId, u.username, t.image, u.avatar as userImage, IFNULL(l.is_cancel, -1) as likeCancel, IFNULL(c.is_cancel, -1) as collectCancel from t_post t left join sys_user u on u.id = t.user_id left join like_record l on t.id = l.target_id and l.target_type = 1 and l.user_id = #{userId} left join collect_record c on c.post_id = t.id and c.user_id = #{userId}
and t.title like concat('%',#{name},'%')
order by t.create_time desc

select l.is_cancel as likeCancel,c.is_cancel as collectCancel
from like_record l left join collect_record c
    on l.user_id = c.user_id and l.target_id = c.post_id
where l.user_id = #{currentId}
and l.target_id = #{postId}
and l.target_type = 1

select t.id,u.username,t.user_id, t.content, t.parent_id, t.to_user_id, t.like_count,t.post_id,u.avatar as userImage,IFNULL(l.is_cancel, -1)
from t_comment t
    left join sys_user u on t.user_id = u.id
    left join like_record l on t.id = l.target_id and l.target_type = 2 and l.user_id=#{userId}
where post_id = #{postId}
